func (m *configModMounts) MarshalJSON() ([]byte, error) {
	var mounts []configModMount

	for _, mount := range m.m.Mounts() {
		mounts = append(mounts, configModMount{
			Source:	mount.Source,
			Target:	mount.Target,
			Lang:	mount.Lang,
		})
	}

	var ownerPath string
	if m.m.Owner() != nil {
		ownerPath = m.m.Owner().Path()
	}

	if m.verbose {
		config := m.m.Config()
		return json.Marshal(&struct {
			Path		string			`json:"path"`
			Version		string			`json:"version"`
			Time		time.Time		`json:"time"`
			Owner		string			`json:"owner"`
			Dir		string			`json:"dir"`
			Meta		map[string]any		`json:"meta"`
			HugoVersion	modules.HugoVersion	`json:"hugoVersion"`

			Mounts	[]configModMount	`json:"mounts"`
		}{
			Path:		m.m.Path(),
			Version:	m.m.Version(),
			Time:		m.m.Time(),
			Owner:		ownerPath,
			Dir:		m.m.Dir(),
			Meta:		config.Params,
			HugoVersion:	config.HugoVersion,
			Mounts:		mounts,
		})
	}

	return json.Marshal(&struct {
		Path	string			`json:"path"`
		Version	string			`json:"version"`
		Time	time.Time		`json:"time"`
		Owner	string			`json:"owner"`
		Dir	string			`json:"dir"`
		Mounts	[]configModMount	`json:"mounts"`
	}{
		Path:		m.m.Path(),
		Version:	m.m.Version(),
		Time:		m.m.Time(),
		Owner:		ownerPath,
		Dir:		m.m.Dir(),
		Mounts:		mounts,
	})
}
